export type Person = {
  slug: string;
  name: string;
  years: string;
  era: string;
  region: string;
  city: string;
  // Coordinates on world map (% of viewBox, see Geo)
  mapX: number;
  mapY: number;
  short: string;
  legacy: string;
  bio: string;
  milestones: string[];
  awards: string[];
  influence: string;
  /** Optional portrait URL (public domain, Wikimedia) */
  portrait?: string;
  /** Подпись под портретом — автор/источник */
  portraitCaption?: string;
  /** Как масштабировать портрет: cover (по умолчанию) или contain */
  portraitFit?: "cover" | "contain";
  /** object-position для портрета, например 'top' или 'center' */
  portraitPosition?: string;
  /** Расширенный текст о значении и влиянии (1-2 абзаца) */
  impactLong?: string;
};

